xpath.script:
// OpenTelemetry Browser Configuration
// These values are injected by the Odoo backend
window.OTEL_ENABLED = ;
window.OTEL_SERVICE_NAME = '';
window.OTEL_SERVICE_VERSION = '';
window.OTEL_DEPLOYMENT_ENVIRONMENT = '';
// Use Odoo proxy endpoint (resolves CORS issues)
// Browser sends traces to Odoo, which forwards to Tempo
window.OTEL_EXPORTER_OTLP_ENDPOINT = window.location.origin + '';
